## 1. 1. Login Scenario: User enters name in Login page and goes to Dashboard page. Username should be visible in Dashboard. Which hook stores the username and which hook navigates to Dashboard?

PROGRAM:


**App.jsx**
```javascript
import { Routes, Route } from "react-router-dom"
import { createContext, useState } from "react"
import Login from "./Login"
import Dashboard from "./Dashboard"

export const nameContext = createContext()

function App() {

  const [name, setName] = useState("")

  return (
    <nameContext.Provider value={{ name, setName }}>

      <Routes>
        <Route path="/" element={<Login />} />
        <Route path="/dashboard" element={<Dashboard />} />
      </Routes>

    </nameContext.Provider>
  )
}

export default App
```

**Login.jsx**

```javascript
import { useContext } from "react"
import { useNavigate } from "react-router-dom"
import { nameContext } from "./App"

function Login() {

  const { name, setName } = useContext(nameContext)

  const navigate = useNavigate()

  function LoginPage() {
    navigate("/dashboard")
  }

  return (
    <div>

      <h1>Login Page</h1>

      <input
        type="text"
        placeholder="Enter Name"
        value={name}
        onChange={(e) => setName(e.target.value)}
      />

      <button onClick={LoginPage}>
        Login
      </button>

    </div>
  )
}

export default Login
```

**Dashboard.jsx**

```javascript
import { useContext } from "react"
import { nameContext } from "./App"

function Dashboard() {

  const { name } = useContext(nameContext)

  return (
    <div>

      <h1>Dashboard</h1>

      <h2>Welcome {name}</h2>

    </div>
  )
}

export default Dashboard
```

